import React, { useState } from 'react';
import { Box, Tabs, Tab, Container, Paper, Typography } from '@mui/material';
import ProductTypeTable from './components/ProductTypeTable';

function App() {
  const [activeTab, setActiveTab] = useState(0);
  const tabs = [
    'Product Type',
    // 'Product',
    // 'Vendor',
    // 'Software Type',
    // 'Software Category',
    // 'Software License Type',
    // 'Asset State',
    // 'Manufacturer',
  ];

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f4f6fb', py: 3 }}>
      <Container maxWidth="xl">
        <Paper elevation={0} sx={{ mb: 3, p: 2, bgcolor: 'transparent' }}>
          <Typography variant="h5" sx={{ mb: 2, fontWeight: 600 }}>
            Product Types
          </Typography>
          <Box sx={{ bgcolor: 'white', borderRadius: 2, boxShadow: 1 }}>
            <Tabs
              value={activeTab}
              onChange={(e, newValue) => setActiveTab(newValue)}
              variant="scrollable"
              scrollButtons="auto"
              aria-label="top navigation tabs"
              sx={{ px: 2 }}
            >
              {tabs.map((tabLabel) => (
                <Tab key={tabLabel} label={tabLabel} sx={{ textTransform: 'none' }} />
              ))}
            </Tabs>
          </Box>
        </Paper>

        <ProductTypeTable />
      </Container>
    </Box>
  );
}

export default App;
